/**
 * Sample a displacement LUT with linear interpolation.
 * @param profile - Profile type
 * @param t - Normalized distance from edge [0, 1]
 * @returns Displacement magnitude [0, 1]
 */
export function sampleLUT(profile: ProfileType, t: number): number {
  const lut = DISPLACEMENT_LUTS[profile];
  const idx = t * (LUT_SAMPLES - 1);
  const i0 = Math.floor(idx);
  const i1 = Math.min(i0 + 1, LUT_SAMPLES - 1);
  const frac = idx - i0;
  return lut[i0] * (1 - frac) + lut[i1] * frac;
}
